-- Templates : message de l'humain AU cochon d'inde du contact, pour son anniversaire
-- animal_type = 'cochon_d_inde' | animal_direction = 'to' | occasion = 'birthday'

insert into public.message_templates
  (user_id, title, content, tone, is_system, is_manual_only, occasion, animal_type, animal_direction)
values

(null, 'Joyeux anniversaire petite(e) merveille.',
$$"Joyeux anniversaire petite(e) merveille." Ton humain m'a envoyé une vidéo de toi ce matin en train de manger du poivron rouge. T'avais l'air d'un gourmet en pleine dégustation. Concentré(e). Sérieux(se). Totalement absorbé(e) par l'expérience. J'ai regardé ça trois fois. Joyeux anniversaire, épicurien(ne) à temps plein.
Avec admiration pour ton rapport au plaisir simple, Ton fan du poivron rouge et de toi 🫑$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'On s''est rencontrés et t''as fait un son que je connaissais pas.',
$$"On s'est rencontrés et t'as fait un son que je connaissais pas." Ton humain a dit que c'était un wheek de curiosité. Que c'était bon signe. J'ai cherché "wheek cochon d'inde" sur internet ce soir-là. J'ai passé deux heures à regarder des vidéos. C'est ta faute. Joyeux anniversaire, responsable de mon nouveau terrier internet.
Avec deux heures de vie bien investies et aucun regret, Celui/celle que t'as rendu(e) accro aux vidéos de cochons d'inde 📺$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'Ton humain t''a fait un plateau de légumes pour ton anniversaire.',
$$"Ton humain t'a fait un plateau de légumes pour ton anniversaire." Poivron. Concombre. Carotte. Persil. Disposés avec soin. Joliment présentés. T'as commencé par le persil. T'as ignoré le concombre. T'as regardé la carotte avec une indifférence polie. Ton humain prenait des notes. Joyeux anniversaire, cobaye culinaire aux préférences précises et évolutives.
Avec respect pour la complexité de tes goûts, Le/la témoin de la prise de notes désespérée de ton humain 📋$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'Je savais pas que les cochons d''inde étaient aussi riches.',
$$"Je savais pas que les cochons d'inde étaient aussi riches." Ton humain m'a expliqué que vous étiez des animaux sociaux. Que vous aviez besoin de compagnie. Que vous communiquiez. Que vous aviez des personnalités distinctes. J'avais une image de petite chose silencieuse dans une cage. T'as tout contredit. Joyeux anniversaire, être infiniment plus riche que prévu.
Avec idées reçues pulvérisées et curiosité rouverte, Celui/celle que tu as instruit(e) sans le savoir 🎓$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'J''ai entendu ton wheek depuis l''entrée en arrivant.',
$$"J'ai entendu ton wheek depuis l'entrée en arrivant." Fort. Clair. Insistant. Ton humain a dit que tu faisais ça quand tu entendais la porte. Que tu reconnaissais les gens. Que tu avais un wheek différent pour chaque personne. J'ai eu le mien. Personnel. Unique. J'en suis fier(fière) comme d'un trophée. Joyeux anniversaire, compositeur(compositrice) de sonneries personnalisées.
Avec mon wheek gravé dans le cœur, Celui/celle qui a eu droit à sa propre mélodie 🎵$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'Ton humain m''a montré comment te tenir.',
$$"Ton humain m'a montré comment te tenir." Y'a une façon. Une bonne façon. On soutient le derrière. On tient bien. On reste bas. On parle doucement. J'ai suivi les instructions à la lettre. T'as regardé devant toi pendant trente secondes avec cet air de dignitaire en visite officielle. C'était majestueux. Joyeux anniversaire, être au protocole strict et justifié.
Avec technique validée et souvenir précieux, Ton porteur/ta porteuse agréé(e) après formation 🤲$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'T''es plus photogénique que la plupart des gens que je connais.',
$$"T'es plus photogénique que la plupart des gens que je connais." Ton humain a un album entier dédié à toi sur son téléphone. J'ai fait défiler. Y'a des photos de toi qui mangent. Qui dorment. Qui regardent dans le vide. Qui font des têtes impossibles. Chacune est meilleure que la précédente. Joyeux anniversaire, modèle naturel(le) sans ego ni agent.
Avec jalousie photographique assumée, Celui/celle qui rate toutes ses photos quand toi t'en rates aucune 📸$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'J''ai appris que vous pouviez mourir de solitude.',
$$"J'ai appris que vous pouviez mourir de solitude." Ton humain me l'a dit avec un sérieux qui m'a marqué(e). Que vous aviez besoin d'un(e) congénère. De présence. De chaleur. De lien. Et j'ai regardé comment ton humain te parle. Te câline. Passe du temps avec toi. Et j'ai compris qu'il/elle avait tout compris. Joyeux anniversaire, être qui inspire le meilleur chez ceux qui t'aiment.
Avec émotion inattendue et admiration pour votre lien, Le/la témoin ému(e) de votre belle histoire 💛$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'T''as fait un popcorning devant moi une fois.',
$$"T'as fait un popcorning devant moi une fois." Ton humain a crié "il/elle popcorne !" J'ai rien compris. Et puis t'as sauté en l'air comme une pop-corn qui éclate. Plusieurs fois. Dans tous les sens. Avec une joie pure et absolue que j'ai rarement vue chez un être vivant. Joyeux anniversaire, champion(ne) olympique de la joie exprimée.
Avec ce moment gravé parmi mes meilleurs souvenirs, Celui/celle que t'as rendu(e) heureux(se) par ricochet 🍿$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to'),

(null, 'Je comprends pas comment quelque chose d''aussi petit peut autant compter.',
$$"Je comprends pas comment quelque chose d'aussi petit peut autant compter." Pour ton humain. Pour moi maintenant. Pour tous ceux qui t'ont rencontré(e). T'as cette faculté rare de t'installer dans les cœurs sans prévenir et d'y rester. Définitivement. Joyeux anniversaire, petit(e) être à l'impact immense et durable.
Avec place réservée dans mon cœur sans que je l'aie vu venir, Ton fan conquis(e) sans résistance possible ❤️$$,
'humorous', true, false, 'birthday', 'cochon_d_inde', 'to');
